frappe.ui.form.on('Vehicle Accident Report', {
	refresh(frm) {
	    if(!frm.doc.__islocal){
        frm.add_custom_button(__("Print"), function () {
                if(frm.doc.parent_company){
                    var letter_head = frm.doc.parent_company
                }
                else{
                    var letter_head = frm.doc.company
                } 
                var f_name = frm.doc.name
                var print_format ="Vehicle Accident Report";
                 window.open(frappe.urllib.get_full_url("/api/method/frappe.utils.print_format.download_pdf?"
                    + "doctype=" + encodeURIComponent("Vehicle Accident Report")
                    + "&name=" + encodeURIComponent(f_name)
                    + "&trigger_print=1"
                    + "&format=" + print_format
                    + "&no_letterhead=0"
                    + "&letterhead=" + encodeURIComponent(letter_head) 
                   ));


            });
	    }
	},
	date(frm){
	    frm.set_value('designation',frm.doc.designation)

	},
	name1(frm){
	    var regex = /[^A-Za-z\s]/g;
		if (regex.test(frm.doc.name1) === true) {
			frappe.msgprint(__("Only Alphabets are allowed."));
			frappe.validated = false;
		}
	},
	to(frm){
	    if(frm.doc.to > frappe.datetime.now_date()){
	        frappe.msgprint(__("Future date is not allowed."));
			frappe.validated = false;
	    }
	},
	company(frm) {
		if (frm.doc.company == "MARAZEEM SECURITY SERVICES" || frm.doc.company == "MARAZEEM SECURITY SERVICES - SHOWROOM" || frm.doc.company == "MARAZEEM SECURITY SERVICES - HO") {
			frm.set_value('letter_head', "MARAZEEM SECURITY SERVICES")
		}
		if (frm.doc.company == "KINGFISHER TRADING AND CONTRACTING COMPANY" || frm.doc.company == "KINGFISHER - TRANSPORTATION" || frm.doc.company == "KINGFISHER - SHOWROOM") {
			frm.set_value('letter_head', "KINGFISHER TRADING AND CONTRACTING COMPANY")
		}
		if (frm.doc.company == "Al - Shaghairi Trading and Contracting Company W.L.L (ELECTRA)" || frm.doc.company == "ELECTRA - BARWA SHOWROOM"|| frm.doc.company == "ELECTRA - ALKHOR SHOWROOM" || frm.doc.company == "ELECTRA - BINOMRAN SHOWROOM" || frm.doc.company == "ELECTRA  - NAJMA SHOWROOM" || frm.doc.company == "ELECTRICAL DIVISION - ELECTRA" || frm.doc.company == "MEP DIVISION - ELECTRA" || frm.doc.company == "STEEL DIVISION - ELECTRA" || frm.doc.company == "TRADING DIVISION - ELECTRA" || frm.doc.company == "INTERIOR DIVISION - ELECTRA" || frm.doc.company == "ENGINEERING DIVISION - ELECTRA" || frm.doc.company == "INDUSTRIAL TOOLS DIVISION") {
			frm.set_value('letter_head', "Electra")
		}
	},

})

frappe.ui.form.on('Employee', {
    date_of_joining(frm){
        frm.trigger("doj_calculation");
    },
    onload(frm){
       frm.trigger("hide_sales_person");
    },
    refresh(frm){
        $("button[data-original-title=Print]").hide();
        frm.trigger("hide_sales_person");
    },
    update_employee_number(frm){
    let d = new frappe.ui.Dialog({
		title: 'Employee Number',
		fields: [
			{
				label: 'Employee Number',
				fieldname: 'employee_number',
				fieldtype: 'Data',
			},
		],
		primary_action_label: __('Save'),
		primary_action: () => {
			let values = d.get_values();
			frappe.call({
				method:"electra.custom.update_employee_no",
				args:{
					'name':frm.doc.name,
					'employee_number':values.employee_number,
				},
				callback: function(r) {
						if(!r.exc) {
							if(r.message) {
								frappe.set_route("Form", "Employee", r.message);
							}
							d.hide();
						}
					}
			})
			d.hide();

		},
	});
	d.show();
	resolve();
    },
    first_name(frm){
        var first_name = frm.doc.first_name;
        var arr = first_name.split(" ");
        for (var i = 0; i < arr.length; i++) {
            arr[i] = arr[i].charAt(0).toUpperCase() + arr[i].slice(1).toLowerCase();
        }
        var str2 = arr.join(" ");
        frm.set_value('first_name',str2);
    },
    last_name(frm){
		var last_name = frm.doc.last_name;
        var arr = last_name.split(" ");
        for (var i = 0; i < arr.length; i++) {
            arr[i] = arr[i].charAt(0).toUpperCase() + arr[i].slice(1).toLowerCase();
        }
        var str2 = arr.join(" ");
        frm.set_value('last_name',str2);
    },
    hide_sales_person(frm){
        var designation = frm.doc.designation;
        if (designation.match("Sales")) {
             frm.set_df_property("sales_person","hidden",false);
        }
        if(frm.doc.designation == "Sales Executive"){
         frm.set_df_property("sales_person","hidden",false);
        }
        else{
            hide_field(['sales_person']);
        }
    },
    sales_person(frm){
	    frappe.call({
			method: 'electra.custom.create_sales_person',
			args: {
				'name': frm.doc.name,
				'department':frm.doc.department,
				'employee':frm.doc.employee_name
			},
			callback(r) {
			    console.log("hi");
			}
		});
    },
    validate(frm){
        frm.trigger("age_calculation");
        if(!frm.doc.__islocal){
        frappe.call({
    		method: "electra.custom.gratuity_calc",
    		args: {
    			employee: frm.doc.employee_number,
    		},
    		callback: function (r) {
    			if (r) {
    			 //   console.log(r)
    			    frm.set_value('gratuity',r.message);
    			}
    		}
			});
        }
        var gross_salary = frm.doc.basic + frm.doc.hra + frm.doc._other_allowance +frm.doc.transportation + frm.doc.accommodation + frm.doc.mobile_allowance;
        var ctc = gross_salary + frm.doc.gratuity + frm.doc.leave_salary + frm.doc.air_ticket_allowance_ + frm.doc.qid_cost + frm.doc.medical_renewal + frm.doc.medical_allowance_ + frm.doc.visa_cost_ + frm.doc.compensationemployee_insurence ;
        var per_hour_cost = ( ctc / (30*8) );
        console.log(ctc);
        frm.set_value("gross_salary",gross_salary);
        frm.set_value("ctc",ctc);
        frm.set_value("per_hour_cost",per_hour_cost);
    },
    basic(frm){
        frm.trigger("ctc")
    },
    hra(frm){
       frm.trigger("ctc") 
    },
    _other_allowance(frm){
       frm.trigger("ctc") 
    },
    transportation(frm){
        frm.trigger("ctc")
    },
    accommodation(frm){
        frm.trigger("ctc")
    },
    mobile_allowance(frm){
       frm.trigger("ctc") 
    },
    gratuity(frm){
      frm.trigger("ctc")  
    },
    leave_salary(frm){
        frm.trigger("ctc")
    },
    air_ticket_allowance_(frm){
        frm.trigger("ctc")
    },
    qid_cost(frm){
       frm.trigger("ctc") 
    },
    medical_renewal(frm){
        frm.trigger("ctc")
    },
    medical_allowance_(frm){
        frm.trigger("ctc")
    },
    visa_cost_(frm){
       frm.trigger("ctc") 
    },
    compensationemployee_insurence(frm){
       frm.trigger("ctc") 
    },
    ctc(frm){
      var gross_salary = frm.doc.basic + frm.doc.hra + frm.doc._other_allowance +frm.doc.transportation + frm.doc.accommodation + frm.doc.mobile_allowance;
      var ctc = gross_salary + frm.doc.gratuity + frm.doc.leave_salary + frm.doc.air_ticket_allowance_ + frm.doc.qid_cost + frm.doc.medical_renewal + frm.doc.medical_allowance_ + frm.doc.visa_cost_ + frm.doc.compensationemployee_insurence ;  
      frm.set_value("ctc",ctc);

    },
    work_location(frm){
        frappe.call({
    		method: "frappe.client.get",
    		args: {
    			doctype: "Work Location",
    			filters: {
    				"work_location": frm.doc.work_location
    			},
    		},
    		callback: function (r) {
    			if (r) {
    			    frm.set_value('holiday_list',r.message.holiday_list);
    			}
    		}
			});
    },
    doj_calculation:function(frm){
        var date = frm.doc.date_of_joining;
        var prob = frappe.datetime.add_days(date, 91);
        frm.set_value('probation_end_date',prob);
    },
	date_of_birth:function(frm){
    	 frm.trigger("age_calculation");
	},
	age_calculation:function(frm){
	    var dob = frm.doc.date_of_birth;  
    	 var birthDate = new Date(dob);
    	 var difference=Date.now() - birthDate.getTime(); 
    	 var  ageDate = new Date(difference); 
    	 var calculatedAge = Math.abs(ageDate.getUTCFullYear() - 1970);
    	 frm.set_value("age",calculatedAge);
    	 if (calculatedAge < 18){
    	     frappe.msgprint("Employee lesser than age 18 will not be allowed");
    	     frappe.validated = false;
    	 }
    },
    grade(frm){
        frappe.call({
        	method: "frappe.client.get",
        	args: {
        		doctype: "Employee Grade",
        		filters: {
        			name: frm.doc.grade,
        		},
        	},
        	callback: function (r) {
        		if (r) {
        		    frm.set_value('visa_cost_',r.message.visa_cost);
        		}
        	}
        });
    },
});

