	future_date_validate:function(frm){
		var today = new Date();
		console.log(today);
		today.setDate(today.getDate());
		var dd = today.getDate();
        var mm = today.getMonth() + 1; 
        var yyyy = today.getFullYear();
        if(dd<10) 
            {
                dd='0'+dd;
            } 

        if(mm<10) 
            {
                mm='0'+mm;
            } 
        today = yyyy+'-'+mm+'-'+dd;
		console.log(frm.doc.possession_date);
		if (frm.doc.possession_date > today){
		    frappe.msgprint("Future Date not Allowed in Date of Possession");
