    mar_dis_per(frm){
        frm.set_value('additional_discount_percentage',frm.doc.mar_dis_per)
        var total = 0
        var sell_total = 0
	    $.each(frm.doc.margin_item,function(i,d){
            total += d.total_cost
            sell_total += d.selling_amount
        })
        frm.set_value('mar_tot_cost',total)
        frm.set_value('mar_gross_tot',sell_total)
        var mar_dis_amt = sell_total * (frm.doc.mar_dis_per/100)
        var diff = frm.doc.mar_gross_tot - frm.doc.mar_dis_amt
        // console.log(mar_dis_amt)
        frm.set_value('mar_dis_amt',mar_dis_amt)
        frm.set_value('total_selling',diff)
        var profit = frm.doc.total_selling - frm.doc.mar_tot_cost
        frm.set_value('margin_profit',profit)
        var perc = (frm.doc.margin_profit / frm.doc.total_selling)*100
        frm.set_value('prof_per',perc)
    },
    mar_dis_amt(frm){
        var perc = (frm.doc.mar_dis_amt / frm.doc.mar_gross_tot)*100
        frm.set_value("mar_dis_per",perc)
        frm.set_value("additional_discount_percentage",frm.doc.mar_dis_per)
    },
