    before_cancel(frm){
        if(frm.doc.cost_estimation){
            frappe.confirm('Did you need to cancel the Cost Estimation?',
    			function () {
        		frappe.call({
        			method: "electra.custom.cancel_ce",
        			freeze: true,
        			freeze_message: __("Cancelling Cost Estimation..."),
        			args: {
        				quotation: frm.doc.name,
        				cost_estimation:frm.doc.cost_estimation,
        			},
        			callback: function (r) {
        				frappe.msgprint(r.message);
        				cur_frm.reload_doc();

        			}
        		});
    		})
        }

        let dialog = new frappe.ui.Dialog({
			title: __('Cancellation Remarks'),
			fields: [
				{
					label: 'Cancellation Remarks',
					fieldtype: 'Small Text',
					fieldname: 'remarks',
				},
			],
			primary_action_label: __('Add'),
			primary_action: () => {
				let values = dialog.get_values();
				if (values) {
					var remarks = values['remarks']
					frm.set_value('remarks',remarks)
				}
				dialog.hide();
			},
		});
		dialog.show();
    },

