						})
						$.each(frm.doc.scope_of_work, function (i, d) {
                        	if (d.total_bidding_price) {
                    			total_bidding_price += d.total_bidding_price
                        	}
                			frm.set_value('total_bidding_price', total_bidding_price)
                    	})
						frm.save()
						frm.save()

					}
				}
	        })
        }
