	validate(frm) {
	    if(frm.doc.amount>frm.doc.grand_total){
            frappe.msgprint("Third Party Amount is Greater than Grand Total");
            frappe.validated = false;
	    }
	    if(frm.doc.__islocal){
            if(frm.doc.customer){
                frappe.call({
                    method:"electra.custom.customer_credit_note",
                    args:{
                        'customer':frm.doc.customer
                    },
                    callback(r){
                        if(r.message){
                            if (r.message.length === 0) {
                                frappe.msgprint(__("Customer's Credit Limit is not set. Please Contact the Accounts Department"));
                                frappe.validated = false;
                            }
                        }
                            
                    }
                })
            }            
        }
	    $.each(frm.doc.items,function(i,j){
	        if(j.item_group == "OptiNor"){
	            j.uom = "Meter"
	        }
	    })
	    frm.refresh_field("items")
	    if(frm.doc.additional_discount_amount > 0){
            frm.set_value('additional_discount_percentage',0)
            frm.set_value('discount_amount',0)
	        var additional_discount_percentage = (frm.doc.additional_discount_amount / frm.doc.grand_total) * 100
            frm.set_value('additional_discount_percentage',additional_discount_percentage)
	    }
	    frm.trigger("calculate_discount_percent")
	    frm.clear_table("payment_schedule")
        frm.refresh_field("payment_schedule")
	    if(frm.doc.order_type == "Sales"){
	        $.each(frm.doc.payment_schedule_2s,function(i,d){
	            d.value=frm.doc.net_total*(d.percentage/100)
	        })
	        frm.refresh_field("payment_schedule_2s")
	    }
	    frm.trigger("validate_dis_tolerance")
	    if(frm.doc.order_type == "Project"){
            frm.trigger("pay_schedule_update")
	        frm.trigger("project_discount_per")
		    frm.trigger("project_discount_amt")
	    }
		
		frm.trigger("bidding_calc")
		frm.trigger("discount_calc")
		
	    var valid_percent = parseInt(frm.doc.percent_total)
	    console.log(valid_percent)
	    if(valid_percent>100){
            frappe.throw(__('Percentage Should not exceed 100%'));
            frappe.validated = false;
        }
	    frm.trigger("sales_user")
	    
		frappe.db.get_value('Quotation', frm.doc.quotation, 'cost_estimation')
			.then(r => {
				if (r.message && Object.entries(r.message).length === 0) {
					frm.set_value("cost_estimation", r.message.cost_estimation)
				}
			})
			
		
	},
