	calculate_payment_terms(frm) {
		if (frm.doc.sales_order && frm.doc.order_type == "Project") {
			frappe.call({
				method: "electra.custom.get_payment_schedule",
				args: {
					"parent": frm.doc.sales_order,
				},
				callback(r) {
					var psi = Object.entries(frm.doc.previous_sales_invoice).length
					if (r.message) {
						$.each(r.message, function (i, d) {
							var index = psi + 1;
							if (d.idx == index) {
								$.each(frm.doc.items, function (j, v) {
									v.qty = (d.percentage / 100) * v.ordered_qty
									frm.refresh_field('items')
								})
							}
						})
					}

				}

			})
		}
        if (frm.doc.invoice_type != 'Cash') {
			frappe.call({
				method: "frappe.client.get_list",
