						$.each(r.message, function (i, d) {
							var adv_amount = (d.advance_percentage / 100) * frm.doc.total
							var ret_amount = (d.retention_percentage / 100) * frm.doc.total
							var net_total_project = frm.doc.total - (adv_amount + ret_amount)
							frm.set_value("adv_amount", adv_amount)
							frm.set_value("ret_amount", ret_amount)
							frm.set_value("net_total_project", net_total_project)
						})
                        if (d.advance_percentage) {
        				    $.each(frm.doc.advances,function(i,j){
                                j.allocated_amount = (d.advance_percentage/100) * frm.doc.grand_total
                            })
                            frm.refresh_field("advances")
        				}
					}
				}
			})
		}
