	set_series(frm) {
		frappe.call({
			method: "electra.utils.get_series",
			args: {
				company: frm.doc.company,
				doctype: frm.doc.doctype
			},
			callback: function (r) {
				if (r) {
				    // console.log(r.message)
					if (frm.doc.is_return) {
						var new_series = r.message
						frm.set_value('naming_series', new_series.replace("STI", "SR"))
					}
					else if (frm.doc.invoice_type == 'Credit') {
						var new_series = r.message
						frm.set_value('naming_series', new_series.replace("STI", "CRD"))
					}
					else if (frm.doc.invoice_type == 'Cash') {
						var new_series = r.message
						frm.set_value('naming_series', new_series.replace("STI", "CSH"))
					}
					else if (frm.doc.invoice_type == 'Credit' && frm.doc.is_return){
						var new_series = r.message
						frm.set_value('naming_series', new_series.replace("STI", "SR-CRD"))
					}
					else if (frm.doc.invoice_type == 'Cash' && frm.doc.is_return){
						var new_series = r.message
						frm.set_value('naming_series', new_series.replace("STI", "SR-CSH"))
					}
					else {
						frm.set_value('naming_series', r.message)
					}
				}
			}
		});
