	invoice_amount(frm,cdt,cdn){
	    var child = locals[cdt][cdn]
	    if (child.invoice_amount){ 
	        child.invoice_percent = (child.invoice_amount / child.total_bidding_price) *100
	    }
	    frm.refresh_field("sow")
	},
	invoice_percent(frm,cdt,cdn){
	    var child = locals[cdt][cdn]
	    if (child.invoice_percent){ 
