frappe.ui.form.on('Consolidated Receivable', {
	customer(frm) {
		frappe.call({
            method :"electra.custom.return_order_invoice",
            args: {
				'customer': frm.doc.customer,
			},

            callback(r){
            if(r.message){
                $.each(r.message[0],function(i,d){
                    if(d.currency == "QAR"){
                        frm.add_child('order_invoice_list',{
                            'type':"Sales Invoice",
                            'name1':d.name,
                            'customer':d.customer,
                            'company':d.company,
                            'date':d.posting_date,
                            'grand_total':d.grand_total,
                            'outstanding_amount':d.outstanding_amount,
                            'outstanding_amount_company_currency':d.outstanding_amount*d.conversion_rate
                        })
                    }
                    frm.refresh_field('order_invoice_list')
                    if(d.currency != "QAR"){
                        frm.add_child('order_invoice_list',{
                            'type':"Sales Invoice",
                            'name1':d.name,
                            'customer':d.customer,
                            'company':d.company,
                            'date':d.posting_date,
                            'grand_total':d.grand_total,
                            'outstanding_amount':d.outstanding_amount,
                            'outstanding_amount_company_currency':d.outstanding_amount*d.conversion_rate
                        })
                    }
                    frm.refresh_field('order_invoice_list')
                })
                console.log(r.message[0])
                $.each(r.message[1],function(i,j){
                    $.each(j,function(i,d){
                        if(d.currency == "QAR"){
                            frm.add_child('order_invoice_list',{
                                'type':"Sales Order",
                                'name1':d.name,
                                'customer':d.customer,
                                'bill_no':"Sales Order",
                                'project_number':d.project,
                                'company':d.company,
                                'date':d.transaction_date,
                                'outstanding_amount':(d.grand_total - d.advance_paid),
                                'grand_total':d.grand_total,
                                'outstanding_amt':(d.grand_total - d.advance_paid)*d.conversion_rate
                            })
                        }
                        frm.refresh_field('order_invoice_list')
                        if(d.currency != "QAR"){
                            frm.add_child('order_invoice_list',{
                                'type':"Sales Order",
                                'name1':d.name,
                                'supplier':d.customer,
                                'bill_no':"Sales Order",
                                'project_number':d.project,
                                'company':d.company,
                                'posting_date':d.transaction_date,
                                'outstanding_amount':(d.grand_total - d.advance_paid),
                                'outstanding_amount_company_currency':(d.grand_total - d.advance_paid)*d.conversion_rate,
                                'grand_total':d.grand_total,
                            })
                        }
                        frm.refresh_field('order_invoice_list')
                    })

                })
                $.each(r.message[2],function(i,d){
                    if(d.total_amount_currency == "QAR"){
                        frm.add_child('order_invoice_list',{
                            'type':"Journal Entry",
                            'name1':d.name,
                            'supplier':d.title,
                            // 'bill_no':d.bill_no,
                            'company':d.company,
                            'posting_date':d.posting_date,
                            'outstanding_amount':d.total_debit,
                            'grand_total':d.total_debit,
                            'outstanding_amt':d.total_debit*frm.doc.exchange_rate
                        })
                    }
                    frm.refresh_field('order_invoice_list')
                    if(d.total_amount_currency != "QAR"){
                        frm.add_child('order_invoice_list',{
                            'type':"Journal Entry",
                            'name1':d.name,
                            'supplier':d.title,
                            // 'bill_no':d.bill_no,
                            'company':d.company,
                            'posting_date':d.posting_date,
                            'outstanding_amount':d.total_debit/frm.doc.exchange_rate,
                            'grand_total':d.total_debit,
                            'outstanding_amt':d.total_debit
                        })
                    }
                    frm.refresh_field('order_invoice_list')
                     frm.save()
                })
                }
            }
        })
	     $.each(frm.doc.order_invoice_list,function(i,j){
            if(j.type == "Sales Order" || j.type == "Sales Invoice"){
                frappe.call({
                    method:"electra.custom.check_for_duplicate_payment",
                    args:{
        				'name':j.name1,
        				'doc_type':j.type,
        				'doc_name':frm.doc.name
                    },
                    callback(r){
                        if(r){
                            $.each(r,function(i,d){
                                console.log(d[1].length)
                                // frappe.msgprint("<b>Row #"+j.idx+"</b><b>"+j.name1+"</b> - Already a Consolidated Payment Request document is there <b>"+d[1]+"</b>")
                            })

                        }
                    }
                })
            }
        })
        frm.save()
	},
	refresh(frm){
	    var d = new Date(new Date().getFullYear(), 0, 1);
        var formattedDate =
          d.getFullYear() +
          '-' +
          ('0' + (d.getMonth() + 1)).slice(-2) +
          '-' +
          ('0' + d.getDate()).slice(-2);
        frm.set_value("transaction_date",formattedDate);

        frm.set_query('bank_account', function() {
			return {
				filters: {
					bank: frm.doc.bank
				}
			};
		});
	    if(frm.doc.customer){
            if(frm.doc.order_invoice_list.length > 0){
                frappe.call({
                    method:"electra.custom.sal_consolidated_req",
                    args:{
        				'name':frm.doc.name
                    },
                    callback(r){
                        if(r){
                            frm.get_field("payment_summary").$wrapper.html(r.message);
                        }
                    }
                })
            }
        }
	},
	chequereference_no(frm){
        $.each(frm.doc.order_invoice_list,function(i,d){
	        d.chequereference_no = frm.doc.chequereference_no
        })
	    frm.refresh_field("order_invoice_list");
	},
	cheque__reference_date(frm){
        $.each(frm.doc.order_invoice_list,function(i,d){
	        d.chequereference_date = frm.doc.cheque__reference_date
        })
	    frm.refresh_field("order_invoice_list");
	},
    grand_total(frm){
        frm.trigger('currency')
    },
    currency(frm){
        frappe.call({
            method :"electra.utils.get_currency_exchange",
            args: {
                'currency': frm.doc.currency,
            },
            callback(r){
                frm.set_value('exchange__rate',r.message)
                frm.set_value('amount_company_currency',frm.doc.exchange__rate * frm.doc.grand_total)
            }
        })
    },
    validate(frm){
        var tot = 0
        var tot_cc = 0
        $.each(frm.doc.order_invoice_list,function(i,j){
            tot += j.receivable_amount
            tot_cc += j.receivable_amount_company_currency
            frm.set_value("receivable_amount",tot)
            frm.set_value("receivable_amount_company_currency",tot_cc)
        })
        $.each(frm.doc.order_invoice_list,function(i,d){
            d.receivable_amount_company_currency = d.receivable_amount * frm.doc.exchange__rate
        })
        frm.refresh_field('order_invoice_list')


