function calculateAndDisplayRoute(directionsService, directionsDisplay, originAddress, destAddress,destinations) {

//   var destinations = [["13.0518068","80.09453049999999"],["13.1740959","80.27970839999999"]];
  var waypts = [];
  var dests = [];
  for (var i = 0; i < destinations.length; i++) {
    var lat = parseFloat(destinations[i][0]);
    var lng = parseFloat(destinations[i][1]);
    dests.push(new google.maps.LatLng(lat, lng));
    waypts.push({
      location: new google.maps.LatLng(lat, lng),
      stopover: true
    });
  }
  var service = new google.maps.DistanceMatrixService();
  directionsService.route({
    origin: originAddress,
    destination: destAddress,
    waypoints: waypts,
    optimizeWaypoints: true,
    travelMode: google.maps.TravelMode.DRIVING
  }, function(response, status) {
    if (status === google.maps.DirectionsStatus.OK) {
      directionsDisplay.setDirections(response);
    } else {
      window.alert('Directions request failed due to ' + status); // Customize your own error here
    }
  });


    service.getDistanceMatrix({
        origins: [originAddress],
        destinations: dests,
        travelMode: google.maps.TravelMode.DRIVING,
        unitSystem: google.maps.UnitSystem.METRIC,
        avoidHighways: false,
        avoidTolls: false
    }, function (response, status) {
        if (status == google.maps.DistanceMatrixStatus.OK && response.rows[0].elements[0].status != "ZERO_RESULTS") {

      var dist_in_mtrs = 0.0;
    //   console.log(response)
      for (var i=0; i<response.rows[0].elements.length; i++) {
        dist_in_mtrs += response.rows[0].elements[i].distance.value;
        }
            var distance = (dist_in_mtrs / 1000);
            cur_frm.set_value("distance_map", distance + " km");
            var dvDistance = document.getElementById("total");
            dvDistance.innerHTML = "";
            dvDistance.innerHTML += " "+distance;

        } else {
            alert("Unable To Find Distance Via Road.");
        }
    });

}

